const mongoose = require("mongoose");
require("dotenv").config();

mongoose.connect(process.env.MONGODB_URI || "mongodb://localhost:27017/theatron")
  .then(() => console.log("✅ Connected to MongoDB"))
  .catch(err => { console.error("❌ Connection error:", err); process.exit(1); });

const movieSchema = new mongoose.Schema({
  title: String, year: Number, genre: [String],
  rating: Number, score: Number, director: String,
  cast: [String], description: String, poster: String,
  duration: Number, language: String, featured: Boolean,
}, { timestamps: true });

