// Deduplicate by title + year
const seen = new Set();
const unique = movies.filter(m => {
  const key = `${m.title.toLowerCase().trim()}-${m.year}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

async function seed() {
  try {
    await Movie.deleteMany({});
    console.log("Cleared existing movies\n");
    const inserted = await Movie.insertMany(unique);
    console.log(`Seeded ${inserted.length} movies successfully!\n`);

    const byGenre = {};
    inserted.forEach(m => m.genre.forEach(g => { byGenre[g] = (byGenre[g] || 0) + 1; }));
    const byLang = {};
    inserted.forEach(m => { byLang[m.language] = (byLang[m.language] || 0) + 1; });

    console.log("Movies by genre:");
    Object.entries(byGenre).sort((a,b) => b[1]-a[1]).forEach(([g,c]) => {
      console.log(`  ${g.padEnd(22)} ${c}`);
    });
    console.log("\nMovies by language:");
    Object.entries(byLang).sort((a,b) => b[1]-a[1]).forEach(([l,c]) => console.log(`  ${l.padEnd(15)} ${c}`));
    console.log("\nTop 5 rated:");
    [...inserted].sort((a,b)=>b.rating-a.rating).slice(0,5).forEach(m => console.log(`  ${m.rating} - ${m.title} (${m.year})`));
  } catch (err) {
    console.error("Seed error:", err.message);
  } finally {
    await mongoose.disconnect();
    console.log("\nDisconnected from MongoDB");
  }
}

seed();
